function searchProducts(e){const t=e.trim().toLowerCase();return t?PRODUCTS.filter(e=>e.name.toLowerCase().includes(t)||e.category.toLowerCase().includes(t)).slice(0,6):[]}function suggestItemHTML(e){return`<a class="suggest-item" href="product.html?id=${e.id}">\n    <div class="s-thumb">${productIconSVG(e.icon)}</div>\n    <div>\n      <h5>${e.name}</h5>\n      <span>${e.category} · ${formatPrice(getStartingPrice(e))}</span>\n    </div>\n  </a>`}function bindSearchBox(e,t){e&&t&&(e.addEventListener("input",()=>{const n=searchProducts(e.value);e.value.trim()?(t.innerHTML=n.length?n.map(suggestItemHTML).join(""):`<div class="suggest-empty">No medicines found for "${e.value}"</div>`,t.classList.add("show")):t.classList.remove("show")}),e.addEventListener("keydown",n=>{if("Enter"===n.key){n.preventDefault();const t=encodeURIComponent(e.value.trim());t&&(window.location.href=`shop.html?q=${t}`)}"Escape"===n.key&&t.classList.remove("show")}),document.addEventListener("click",n=>{t.contains(n.target)||n.target===e||t.classList.remove("show")}))}document.addEventListener("DOMContentLoaded",()=>{bindSearchBox(document.getElementById("navSearchInput"),document.getElementById("navSearchSuggest"))});